ctype=collections.Counter(); cname=collections.Counter(); pairs=collections.Counter()
for line in open("output/cognee_codex_full_bundle/edges.jsonl"):
    e=json.loads(line)
    s=nodes[e["source_id"]]; t=nodes[e["target_id"]]
    st=s["metadata"].get("research_node_type","Unknown")
    tt=t["metadata"].get("research_node_type","Unknown")
    ctype[(st,e["relationship"],tt)] += 1
    if st in {"ResearchField","ResearchTopic","MethodologicalConcept","ApproachFamily","TechnicalTerm"} and tt in {"ResearchField","ResearchTopic","MethodologicalConcept","ApproachFamily","TechnicalTerm"}:
        pairs[(s["name"],e["relationship"],t["name"])] += 1
print("top type triples:")
for k,v in ctype.most_common(20): print(v,k)
print("top concept pairs:")
for k,v in pairs.most_common(20): print(v,k)
